const text = $input.first().json.candidates[0].content.parts[0].text;
let parsed = {};

try {
  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && firstBrace < 200) {
    const jsonString = text.substring(firstBrace, lastBrace + 1);
    const tempParsed = JSON.parse(jsonString);
    if (tempParsed.title || tempParsed.content) {
      parsed = tempParsed;
    }
  }
} catch(e) {}

if (!parsed.title) {
  const extract = (regex) => {
    const match = text.match(regex);
    return match ? match[1].trim() : "";
  };

  parsed = {
    id: extract(/Prompt number:\s*(.*?)(?=\n|$)/i),
    title: extract(/Title:\s*(.*?)(?=\n|$)/i),
    content: extract(/Prompt:\s*([\s\S]*?)(?=JSON Prompt:)/i),
    json_prompt: extract(/JSON Prompt:\s*([\s\S]*?)(?=Tags:)/i),
    tags: extract(/Tags:\s*(.*?)(?=\n|$)/i),
    category: extract(/(?:Sub-theme \/ Category:|Category:)\s*(.*?)(?=\n|$)/i),
    theme: extract(/Theme:\s*(.*?)(?=\n|$)/i),
    group: extract(/Group:\s*(.*?)(?=\n|$)/i),
    share_text_twitter: extract(/(?:X share text:|Twitter share text:)\s*([\s\S]*?)(?=Facebook share text:)/i),
    share_text_facebook: extract(/Facebook share text:\s*([\s\S]*?)(?=Pinterest share text:)/i),
    share_text_pinterest: extract(/Pinterest share text:\s*([\s\S]*?)(?=Whatsapp share text:)/i),
    share_text_whatsapp: extract(/Whatsapp share text:\s*([\s\S]*?)(?=$)/i)
  };

  // ```text ve ``` ifadelerini content'ten temizle
  if (parsed.content) {
    parsed.content = parsed.content.replace(/```text/gi, '').replace(/```/g, '').trim();
  }
  // json_prompt'tan backtick'leri temizle
  if (parsed.json_prompt) {
    parsed.json_prompt = parsed.json_prompt.replace(/```json/gi, '').replace(/```/g, '').trim();
  }
  // Etiketleri temizle: ["tag1","tag2"] → tag1,tag2
  if (parsed.tags) {
    parsed.tags = parsed.tags.replace(/[\[\]"]/g, '').trim();
  }
}

return { json: parsed };

for (const item of $input.all()) {
  const jsonContent = JSON.stringify($node["Parse JSON"].json, null, 2);
  item.binary = {
    data: {
      data: Buffer.from(jsonContent).toString('base64'),
      mimeType: 'application/json',
      fileName: 'prompt_data.json'
    }
  };
}
return $input.all();
